<?php error_reporting(E_ALL); ini_set("display_errors", "1"); require "conn.php"; $UserLat = 0; $UserLongt = 0; $res = mysqli_query($con, "SELECT count(*) as c FROM Shops JOIN Posts ON Shops.ShopID=Posts.ShopID LEFT JOIN Foods ON Posts.ProductID = Foods.FoodID JOIN Categories ON Shops.CategoryID = Categories.CategoryId WHERE Shops.Status = 'ACTIVE' AND Posts.PostStatus='ACTIVE' AND (Posts.Video IS NULL OR Posts.Video = '' OR Posts.Video = '0' OR Posts.Video = 'NONE') HAVING (6372.797 * acos(cos(radians($UserLat)) * cos(radians(ShopLat)) * cos(radians(ShopLongt) - radians($UserLongt)) + sin(radians($UserLat)) * sin(radians(ShopLat)))) <= 10050"); if (!$res) echo mysqli_error($con); else var_dump(mysqli_fetch_assoc($res)); ?>
